:root {
  /* Farben */
  --cream: #f5efe8;          /* Standard-Seitenhintergrund */
  --soft-beige: #eedfcc;     /* Sekundärfläche / Footer */
  --waffle-peach: #E4C0A8;   /* Akzentfläche / Platzhalter */
  --terracotta: #CC624C;     /* Primärfarbe / CTA */
  --terracotta-dark: #b5523d;/* Hover-Zustand */
  --dark: #2d1f19;           /* Überschriften */
  --dark-mid: #5c3d35;       /* Fließtext */
  --dark-soft: #9a7060;      /* Sekundärtext */
  --white: #fefefe;
  /* Typografie */
  --font-display: 'Calistoga', serif;
  --font-body: 'Nunito', sans-serif;
  /* Radien */
  --radius-sm: 12px;  --radius-md: 20px;
  --radius-lg: 32px;  --radius-pill: 100px;
  /* Schatten */
  --shadow-sm: 0 2px 12px rgba(45,31,25,0.06);
  --shadow-md: 0 6px 28px rgba(45,31,25,0.10);
  --shadow-lg: 0 12px 48px rgba(45,31,25,0.14);
  --shadow-terra: 0 8px 32px rgba(204,98,76,0.22);
  /* Easing */
  --ease-sp …

.hf-swatches { display: grid; grid-template-columns: repeat(auto-fill, minmax(150px,1fr)); gap: 14px; }
.hf-sw { display: flex; flex-direction: column; gap: 6px; }
.hf-sw span { height: 64px; border-radius: 12px; box-shadow: inset 0 0 0 1px rgba(45,31,25,0.08); }
.hf-sw b { font: 700 12px var(--font-body); color: var(--dark); }
.hf-sw i { font: 500 11px ui-monospace, monospace; color: var(--dark-soft); font-style: normal; }

.hf-type { display: flex; flex-direction: column; }
.hf-type-h1 { font: 400 clamp(2.2rem,6vw,4rem)/1.1 var(--font-display); color: var(--dark); }
.hf-type-h2 { font: 400 clamp(1.7rem,4vw,2.8rem)/1.1 var(--font-display); color: var(--dark); margin-top: 18px; }
.hf-type-body { font: 400 1rem/1.7 var(--font-body); color: var(--dark-mid); max-width: 46ch; margin-top: 18px; }
.hf-type-strong { font: 800 1rem var(--font-body); color: var(--dark); margin-top: 18px; }
.hf-type-meta { font: 500 11px ui-monospace, monospace; color: var(--dark-soft); margin-top: 4px; }

.hf-rs { display: grid; grid-template-columns: repeat(auto-fill, minmax(120px,1fr)); gap: 18px; }
.hf-rs div { display: flex; flex-direction: column; gap: 8px; align-items: center; }
.hf-rs-box { width: 100%; height: 72px; background: var(--white); border: 1px solid #eedfcc; }
.hf-rs i { font: 500 11px ui-monospace, monospace; color: var(--dark-soft); font-style: normal; }

.hf-bite-demo { position: relative; display: inline-block; }
.hf-bite-pill { background: #CC624C; color: #fefefe; font: 800 .9rem var(--font-body); padding: 12px 26px; border-radius: 100px; }
.hf-bite-notch { position: absolute; bottom: -1px; left: 16px; width: 18px; height: 18px; border-radius: 50%; background: #f5efe8; /* = Sektions-BG */ }

.hf-btn-wrap { position: relative; display: inline-flex; }
.hf-btn-primary { position: relative; z-index: 1; background: #CC624C; color: #fefefe; font: 800 .9rem var(--font-body); letter-spacing: -.01em; border: none; padding: 13px 30px; border-radius: 100px; cursor: pointer; white-space: nowrap; box-shadow: 0 3px 12px rgba(204,98,76,.18); transition: all .28s var(--ease-spring); }
.hf-btn-wrap:hover .hf-btn-primary { background: #b5523d; transform: scale(1.05) translateY(-1px); box-shadow: 0 8px 28px rgba(204,98,76,.34); }
.hf-btn-primary:active { transform: scale(.95); }
.hf-btn-wrap::after { content: ''; position: absolute; z-index: 2; bottom: -1px; left: 14px; width: 18px; height: 18px; border-radius: 50%; background: var(--bite, #f5efe8); transform: scale(0); transform-origin: center bottom; transition: transform .25s var(--ease-spring); pointer-events: none; }
.hf-btn-wrap:hover::a …

.hf-btn-secondary { background: transparent; color: #CC624C; font: 800 .9rem var(--font-body); border: 2px solid #CC624C; padding: 11px 28px; border-radius: 100px; cursor: pointer; white-space: nowrap; transition: all .2s ease; }
.hf-btn-secondary:hover { background: #CC624C; color: #fefefe; }
.hf-btn-secondary:active { transform: scale(.95); }

.hf-tag { display: inline-flex; align-items: center; font: 800 .72rem var(--font-body); letter-spacing: .02em; padding: 5px 13px; border-radius: 100px; white-space: nowrap; }
.hf-tag--terra { background: #CC624C; color: #fefefe; }
.hf-tag--outline { background: transparent; color: #CC624C; box-shadow: inset 0 0 0 1.5px #CC624C; }
.hf-tag--dark { background: #2d1f19; color: #fefefe; }

.hf-rating { display: inline-flex; align-items: center; gap: 8px; font-family: var(--font-body); }
.hf-stars { color: #CC624C; font-size: 1.05rem; letter-spacing: 1px; position: relative; }
.hf-star-half { color: #E4C0A8; }
.hf-rating b { font-weight: 800; color: #2d1f19; }
.hf-rating i { font-style: normal; font-weight: 600; font-size: .82rem; color: #9a7060; }

.hf-sectitle { text-align: center; }
.hf-sectitle h2 { font: 400 clamp(1.7rem,4vw,2.8rem)/1.1 var(--font-display); color: #2d1f19; margin-bottom: 8px; }
.hf-sectitle p { font: 400 .92rem/1.65 var(--font-body); color: #9a7060; max-width: 440px; margin: 0 auto; }
.hf-sectitle--light h2 { color: #f5efe8; }
.hf-sectitle--light p { color: rgba(245,239,232,.75); }

.hf-ticket { position: relative; border: 2px dashed #CC624C; border-radius: 20px; background: #fff; overflow: visible; margin: 0 14px; max-width: 380px; }
.hf-ticket-body { padding: 24px 28px; }
.hf-ticket-hole { position: absolute; top: 50%; transform: translateY(-50%); width: 26px; height: 26px; border-radius: 50%; background: var(--ticket-bg, #f5efe8); border: 2px dashed #E4C0A8; }
.hf-ticket-hole--l { left: -14px; }
.hf-ticket-hole--r { right: -14px; }

.hf-quickinfo { background: #eedfcc; border-radius: 16px; padding: 16px 20px; max-width: 320px; }
.hf-qi-strong { font: 700 .85rem var(--font-body); color: #5c3d35; }
.hf-qi-soft { font: 400 .8rem var(--font-body); color: #9a7060; margin-top: 3px; }

.hf-blob { border-radius: 42% 58% 63% 37% / 41% 44% 56% 59%; animation: hf-blobFloat 9s ease-in-out infinite; }
@keyframes hf-blobFloat {
  0%,100% { transform: translate(0,0) scale(1); }
  33%     { transform: translate(6px,-10px) scale(1.02); }
  66%     { transform: translate(-5px,7px) scale(0.98); }
}

.hf-header { background: rgba(245,239,232,.96); backdrop-filter: blur(16px); border-bottom: 1px solid #eedfcc; }
.hf-header-inner { max-width: 1200px; margin: 0 auto; padding: 0 24px; height: 68px; display: flex; align-items: center; justify-content: space-between; gap: 16px; }
.hf-nav { display: flex; align-items: center; gap: 4px; }
.hf-nav a { font: 600 .87rem var(--font-body); color: #5c3d35; padding: 8px 18px; border-radius: 50px; cursor: pointer; white-space: nowrap; transition: all .2s ease; }
.hf-nav a:hover { background: rgba(238,223,204,.6); }
.hf-nav a.is-active { background: #eedfcc; color: #CC624C; font-weight: 800; }
@media (max-width: 768px) { .hf-nav { display: none; } }

.hf-footer { background: #eedfcc; padding: 48px 32px 36px; }
.hf-footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px,1fr)); gap: 36px; margin-bottom: 36px; }
.hf-footer-h { font: 400 1.05rem var(--font-display); color: #CC624C; margin-bottom: 14px; }
.hf-footer-link { display: block; font: 600 .87rem var(--font-body); color: #5c3d35; margin-bottom: 9px; cursor: pointer; }
.hf-footer-link:hover { color: #CC624C; }
.hf-footer-c { font: 600 .84rem var(--font-body); color: #5c3d35; margin-bottom: 8px; }
.hf-footer-bottom { border-top: 1px solid #E4C0A8; padding-top: 20px; display: flex; flex-wrap: wrap; gap: 14px; justify-content: space-between; align-items: center; }
.hf-footer-legal { font: 400 .76rem var(--font-body); color: #9a7060; cursor: pointer; }

.hf-container { max-width: 1200px; margin: 0 auto; padding: 0 24px; }
.hf-section-pad { padding: 80px 0; }
.hf-grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: center; }
.hf-grid-3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 28px; }
.hf-grid-4 { display: grid; grid-template-columns: repeat(4,1fr); gap: 24px; }
@media (max-width: 900px) { .hf-grid-2 { grid-template-columns: 1fr; } .hf-grid-3 { grid-template-columns: 1fr 1fr; } }
@media (max-width: 560px) { .hf-grid-3, .hf-grid-4 { grid-template-columns: 1fr; } }
/* Demo-Hilfsklasse (nicht übernehmen): */
.hf-gh-cell { background: #E4C0A8; color: #CC624C; font: 800 .9rem var(--font-body); height: 48px; display: flex; align-items: center; justify-content: center; border-radius: 10px; }

.hf-lava-line { position: relative; width: 100%; height: 88px; overflow: hidden; }
.hf-lava-line .flow { position: absolute; top: 0; left: 0; width: 200%; height: 100%; }
.hf-lava-line .flow svg { display: block; width: 100%; height: 100%; }
.hf-lava-line .flow path { fill: none; stroke-width: 22; stroke-linecap: round; stroke-linejoin: round; vector-effect: non-scaling-stroke; }
.hf-lava-line .flow-b { animation: hf-wave-r 21s linear infinite; opacity: .5; }
.hf-lava-line .flow-b path { stroke: var(--lava2, #E4C0A8); }
.hf-lava-line .flow-f { animation: hf-wave-l 14s linear infinite; }
.hf-lava-line .flow-f path { stroke: var(--lava, #CC624C); }
@keyframes hf-wave-l { from { transform: translateX(0); } to { transform: translateX(-50%); } }
@keyframes hf-wave-r { from { transform: translateX(-50%); } to { transform: translateX(0); } }
