.hf-lava-band { position: relative; width: 100%; height: 150px; overflow: hidden; }
.hf-lava-band .flow { position: absolute; top: 0; left: 0; width: 200%; height: 100%; }
.hf-lava-band .flow svg { display: block; width: 100%; height: 100%; }
.hf-lava-band .flow-b { animation: hf-wave-r 26s linear infinite; }
.hf-lava-band .flow-b path { fill: var(--lava2, #EAD2BE); }
.hf-lava-band .flow-f { animation: hf-wave-l 17s linear infinite; }
.hf-lava-band .flow-f path { fill: var(--lava, #E4C0A8); }
@keyframes hf-wave-l { from { transform: translateX(0); } to { transform: translateX(-50%); } }
@keyframes hf-wave-r { from { transform: translateX(-50%); } to { transform: translateX(0); } }
@media (prefers-reduced-motion: reduce) { .hf-lava-band .flow { animation-play-state: paused; } }
